      'jalaycalmp',
      'clojurermt',
    ]
    const expectedResults = {
      clojure: {
        start: [10, 1],
        end: [10, 7],
      },
      elixir: {
        start: [5, 6],
        end: [5, 1],
      },
      ecmascript: {
        start: [1, 10],
        end: [10, 10],
      },
    }
    const wordSearch = new WordSearch(grid)
    expect(wordSearch.find(['elixir', 'clojure', 'ecmascript'])).toEqual(
      expectedResults
    )
  })

